  "task_summary": "To read a text file path in a Node.js environment and return line count, word count, and character count.",
  "approach": "This function reads the contents of a file using `fs.readFile()`, then splits the file into lines using `split('
')`. It then counts the number of lines, words, and characters. If the file is empty or does not exist, it returns appropriate error messages."
  ,
  "code": "import fs from 'fs';

function readFileSync(filePath: string): { lineCount: number, wordCount: number, characterCount: number } {
  try {
    const content = fs.readFileSync(filePath, 'utf8');
    if (!content) {
      throw new Error(`File ${filePath} does not exist or could not be read.
`);
    }

    const lines = content.split('
').map(line => line.trim()).filter(line => line.length > 0); // Trim leading and trailing whitespace from each line.
    const wordCount = lines.reduce((total, line) => total + line.split(/  /).length, 0);

    return { lineCount, wordCount, characterCount };
  } catch (error) {
    throw new Error(`An error occurred while reading the file: ${error.message}
`);
  }
}",
