from collections import OrderedDict
class LRUCache:
    def __init__(self, capacity: int = 10):
        self.capacity = capacity
        # Initialize the cache with a dictionary to store items
        self.cache = OrderedDict()

    def get(self, key: str) -> object or None:
        if key in self.cache:
            # If the key exists in the cache, move it to the end of the list (LRU order)
            self.cache.move_to_end(key)
            return self.cache[key]
        return None

    def put(self, key: str, value: object) -> None:
        if key in self.cache:
            # If the key exists in the cache, update its value and move it to the end of the list (LRU order)
            self.cache[key] = value
            self.cache.move_to_end(key)
        else:
            # If the key does not exist in the cache, check if adding the new item would exceed the capacity
            if len(self.cache) >= self.capacity:
                # If it does, remove the least recently used item (LIFO order)
                del self.cache.popitem(last=False)
            # Add the new item to the end of the list (LRU order)
            self.cache[key] = value

    def __str__(self) -> str:
