  "code": "def min_edit_distance(s1: str, s2: str) -> int:
    # If either string is empty, return its length
    if len(s1) == 0 or len(s2) == 0:
        return len(s1) + len(s2)

    # Initialize the DP table with a list of lists containing -1 values for each cell
    dp = [[float('inf')] * (len(s2) + 1) for _ in range(len(s1) + 1)]

    # Fill the first row and first column with the lengths of the strings
    for i in range(1, len(s1) + 1):
        dp[i][0] = i
    for j in range(1, len(s2) + 1):
        dp[0][j] = j

    # Fill the DP table using the recurrence relation
    for i in range(1, len(s1) + 1):
        for j in range(1, len(s2) + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1]
            else:
                dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + 1
    return dp[len(s1)][len(s2)]

    # Backtrack to find the optimal sequence
    def backtrack(i: int, j: int) -> str:
        if i == 0 or j == 0:
            return "","

        if s1[i-1] == s2[j-1]:
            return backtrack(i-1, j-1)
        else:
            seq = [s1[i-1], s2[j-1]]
            if dp[i][j-1] < dp[i-1][j]
                seq.append(backtrack(i-1, j))
            elif dp[i][j-1] > dp[i-1][j]
                seq.append(backtrack(i, j-1))
            return seq
    # Find the optimal sequence and print it
    optimal_seq = backtrack(len(s1), len(s2))[0] + backtrack(len(s2), len(s1))[1]
    return optimal_seq

    # Test cases
