USE support_system;

-- Create tables for categories, tags, and tickets
CREATE TABLE categories (
    category_id INT PRIMARY KEY AUTO_INCREMENT,
    category_name VARCHAR(255)
);

CREATE TABLE tags (
    tag_id INT PRIMARY KEY AUTO_INCREMENT,
    tag_name VARCHAR(255)
);

-- Create a table to store ticket details
CREATE TABLE tickets (
    ticket_id INT PRIMARY KEY AUTO_INCREMENT,
    category_id INT,
    title VARCHAR(255),
    description TEXT,
    priority ENUM('Low', 'Medium', 'High'),
    status ENUM('Pending', 'Resolved', 'Closed'),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

-- Insert data into the categories table
INSERT INTO categories (category_name) VALUES ('General'), ('Technical'), ('Support'), ('Customer Service'), ('Marketing');

-- Insert data into the tags table
