-- Insert data into the tickets table
INSERT INTO tickets (category_id, title, description, priority, status, created_at, updated_at) VALUES
(1, 'New Feature Request', 'Bug in website that needs fixing.', 'Low', 'Pending', NOW(), NOW()),
(2, 'Feature Request', 'Add new feature to chatbot.', 'Medium', 'Resolved', NOW(), NOW()),
(3, 'Documentation Update', 'Need clarification on how to use the API.', 'High', 'Closed', NOW(), NOW());

-- Helper query set to retrieve and sum up counts of tickets per category based on their tags
SELECT t.category_name, COUNT(*) AS total_count
FROM categories t
JOIN tickets t1 ON t.category_id = t1.category_id
JOIN tags t2 ON t1.tag_id = t2.tag_id
