  "task_summary": "Implement a lightweight job scheduler with priorities, retry limits, and failure callbacks using only standard library capabilities available in Node.js.",
  "approach": "Use `setTimeout` to schedule tasks based on their priority, `setInterval` for periodic tasks, and `process.nextTick` for deferred work.",
  "code": "const { setTimeout, setInterval } = require('timers');

class JobScheduler {
  constructor() {
    this.tasks = []; // Array of scheduled tasks
    this.retryLimit = 3; // Maximum number of retries for each task before failure
  }

  scheduleTask(priority: number, task: () => void) { // Schedule a task with priority and callback
    const scheduledTask = { priority, task, retries: 0 };
    this.tasks.push(scheduledTask);
    if (this.tasks.length > this.retryLimit) { // Check for maximum retry limit
      this.runNextTick(); // Retry next scheduled task
    } else { // Run the first scheduled task if not exceeded retries
      this.runScheduledTask(); // Run the first scheduled task immediately
    }
  }

  runScheduledTask() { // Run the first scheduled task if not exceeded retries
    const [task, priority] = this.tasks.shift();
    const startTime = Date.now();
    try { // Attempt to execute the task
      await task();
      console.log(`Task ${priority} completed successfully at ${new Date().toLocaleTimeString()}`);
      if (this.retryLimit > 0) { // Retry after a certain time
        setTimeout(() => this.runScheduledTask(), priority * 1000); // Retry after the next scheduled task
      } else { // Run immediately after the first scheduled task
        console.log(`Task ${priority} completed successfully at ${new Date().toLocaleTimeString()}`);
      }
    } catch (error) { // Handle exceptions
      if (this.retryLimit > 0) { // Retry after a certain time
        setTimeout(() => this.runScheduledTask(), priority * 1000); // Retry after the next scheduled task
      } else { // Run immediately after the first scheduled task
        console.error(`Task ${priority} failed at ${new Date().toLocaleTimeString()}`, error);
      }
    }
  }

  runNextTick() { // Run the first scheduled task immediately if not exceeded retries
    const [task, priority] = this.tasks.shift();
    setTimeout(() => this.runScheduledTask(), priority * 1000); // Schedule next scheduled task
  }
}

const jobScheduler = new JobScheduler();
jobScheduler.scheduleTask(1, () => { console.log('Task 1 completed successfully at ' + new Date().toLocaleTimeString()); });
jobScheduler.scheduleTask(2, () => { console.log('Task 2 completed successfully at ' + new Date().toLocaleTimeString()); });

console.log(jobScheduler.tasks); // Output: [{ priority: 1, task: () => console.log('Task 1 completed successfully at ' + new Date().toLocaleTimeString()) }, { priority: 2, task: () => console.log('Task 2 completed successfully at ' + new Date().toLocaleTimeString()) }]
