  "code": "import { setImmediate, setTimeout, setInterval } from 'timers';

const jobScheduler = (options: { initialDelay?: number; priority?: number; retries?: number; successCallback?: () => void; errorCallback?: () => void }) => {
  if (!options.initialDelay) return;
  const now = Date.now();
  let toBeScheduled = options.initialDelay + now;

  function runJob() {
    try {
      // Schedule the next job or call the success callback after waiting for it to resolve.
      setTimeout(() => runJob(), options.priority || 100);
    } catch (error) {
      if (!options.errorCallback) throw error;
      options.errorCallback();
    }
    console.log(`Job scheduled: ${runJob.name}
`);
  }

  // Schedule the job to run at some time in the future.
  const interval = setInterval(() => {
    toBeScheduled += options.retries * 1000;
    if (toBeScheduled > Date.now()) return;
    runJob();
  }, options.priority || 100);

  // Run initial scheduled job after a delay.
  setTimeout(runJob, options.initialDelay);
}

export default jobScheduler;",
