  const fileTypes = new Map();
  const largestFiles = new Map();
  const likelySecretExposures = new Set();
  const unreadableFiles = new Set();

  directoryListing.forEach(fileMetadata => {
    const { type, size, lastModified } = fileMetadata;

    if (type === 'file') {
      fileTypes.set(type, (fileTypes.get(type) || 0) + 1);
    } else if (type === 'directory') {
      largestFiles.set(type, Math.max(largestFiles.get(type), size));
    } else if (type === 'secret') {
      likelySecretExposures.add(fileMetadata.name);
    } else if (type === 'unreadable') {
      unreadableFiles.add(fileMetadata.name);
    }
  });

